   165→# Check if a specific adapter command is available in PATH
   166→def is_adapter_available [
   167→  adapter: string  # Adapter name (claude, ollama, or codex)
   168→]: nothing -> bool {
   169→  # Check if command exists
   170→  let cmd_result = (do { ^which $adapter } | complete)
   171→  if $cmd_result.exit_code != 0 {
   172→    return false
   173→  }
   174→
   175→  # Additional checks per adapter
   176→  if $adapter == "ollama" {
   177→    # Check if ollama server is running
   178→    let server_result = (do { ^curl -sf http://localhost:11434/api/tags } | complete)
   179→    return ($server_result.exit_code == 0)
   180→  } else if $adapter == "codex" {
   181→    # Check if OPENAI_API_KEY is set
   182→    return ("OPENAI_API_KEY" in $env)
   183→  } else {
   184→    # claude or other adapters: just check command existence
   185→    return true
   186→  }
   187→}
   188→
   189→# Get list of available adapters from the standard set
   190→def get_available_adapters []: nothing -> list<string> {
   191→  ["claude", "ollama", "codex"]
   192→  | where { |adapter| (is_adapter_available $adapter) }
   193→}
   194→
   195→# Get path to the bop binary
   196→def get_bop_bin []: nothing -> path {
   197→  let root = ($env.CURRENT_FILE | path dirname | path dirname)
   198→  $root | path join "target" "debug" "bop"
   199→}
   200→
   201→# Get path to the repository root
   202→def get_repo_root []: nothing -> path {
   203→  $env.CURRENT_FILE | path dirname | path dirname
   204→}
   205→
   206→# Get path to an adapter script
   207→def get_adapter_path [
   208→  adapter: string  # Adapter name (e.g., "mock", "claude", "ollama")
   209→]: nothing -> path {
   210→  let root = (get_repo_root)
   211→  $root | path join "adapters" $"($adapter).nu"
   212→}
   213→
   214→# Build the bop binary before running tests
   215→def build_bop []: nothing -> nothing {
   216→  let root = (get_repo_root)
   217→  let result = (do {
   218→    cargo build
   219→  } | complete)
   220→
   221→  if $result.exit_code != 0 {
   222→    error make {
   223→      msg: "Failed to build bop binary"
   224→      label: {
   225→        text: $"cargo build failed with exit code ($result.exit_code)"
   226→        span: (metadata $result).span
   227→      }
   228→    }
   229→  }
   230→}
   231→
   232→# Create a test setup with temp directory, .cards structure, and providers.json
   233→def create_test_setup [
   234→  adapter: string  # Primary adapter to use (e.g., "mock", "claude")
   235→]: nothing -> record<cards_dir: path, temp_dir: path> {
   236→  # Create temp directory
   237→  let temp_dir = (mktemp -d)
   238→  let cards_dir = ($temp_dir | path join ".cards")
   239→
   240→  # Initialize .cards directory
   241→  let bop = (get_bop_bin)
   242→  let init_result = (do {
   243→    ^$bop --cards-dir $cards_dir init
   244→  } | complete)
   245→
   246→  if $init_result.exit_code != 0 {
   247→    error make {
   248→      msg: "Failed to initialize .cards directory"
   249→      label: {
   250→        text: $"bop init failed with exit code ($init_result.exit_code)"
   251→        span: (metadata $init_result).span
   252→      }
   253→    }
   254→  }
   255→
   256→  # Write providers.json
   257→  write_providers $cards_dir $adapter
   258→
   259→  {cards_dir: $cards_dir, temp_dir: $temp_dir}
   260→}
   261→
   262→# Write providers.json with the specified adapter
   263→def write_providers [
   264→  cards_dir: path   # Path to .cards directory
   265→  adapter: string   # Adapter name (e.g., "mock", "claude")
   266→]: nothing -> nothing {
   267→  let adapter_path = (get_adapter_path $adapter)
   268→  let adapter_str = ($adapter_path | str replace --all '\\' '\\\\')
